noncompliant:
#include <vector>
#include <string>

class Registry {
  std::vector<std::string> names;
public:
  template <typename StringLike>
  void addName(StringLike&& arg) {
    names.emplace_back(arg); // Noncompliant - not forwarding the parameter
    // This ignores rvalue-ness of the argument
  }
};

compliant:
#include <vector>
#include <string>
#include <utility>

class Registry {
  std::vector<std::string> names;
public:
  template <typename StringLike>
  void addName(StringLike&& arg) {
    names.emplace_back(std::forward<StringLike>(arg)); // Compliant - proper forwarding
  }

  // Or use separate overloads instead of forwarding reference
  void addName(const std::string& name) {
    names.emplace_back(name);
  }

  void addName(std::string&& name) {
    names.emplace_back(std::move(name));
  }
};
